import scala.math.BigDecimal

object AccountActor {
  // --- Messages ---
  sealed trait Command
  case class Deposit(amount: BigDecimal) extends Command
  case class Withdraw(amount: BigDecimal) extends Command
  case object GetBalance extends Command // To query the current balance

  sealed trait Response
  case class BalanceUpdated(newBalance: BigDecimal) extends Response
  case class CurrentBalance(balance: BigDecimal) extends Response
  case object InsufficientFunds extends Response
  case object InvalidAmount extends Response // For non-positive deposit/withdrawal amounts

  /**
