class AccountActor(initialBalance: BigDecimal) extends Actor with ActorLogging {
  import AccountActor._

  // Mutable state: the account balance.
  // This 'var' is safe in an Akka actor because actors process messages sequentially,
  // ensuring single-threaded access to its internal state.
  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount <= BigDecimal(0)) {
        sender() ! InvalidAmount
        log.warning(s"Received invalid deposit amount: $amount")
      } else {
        balance += amount
        sender() ! BalanceUpdated(balance)
        log.info(s"Deposited $amount. New balance: $balance")
